import os
import requests
import torch
import torch.nn as nn
from torchvision import models, transforms
from torch.utils.data import DataLoader, Dataset
from torchvision.datasets import ImageFolder
from torch.optim import Adam

class CustomDataset(Dataset):
    def __init__(self, root_dir, transform=None):
        self.dataset = ImageFolder(root=root_dir, transform=transform)
        self.transform = transform

    def __len__(self):
        return len(self.dataset)

    def __getitem__(self, idx):
        img, label = self.dataset[idx]
        if self.transform:
            img = self.transform(img)
        return img, label

def download_model(url, save_path):
    response = requests.get(url, stream=True)
    if response.status_code == 200:
        with open(save_path, 'wb') as f:
            for chunk in response.iter_content(1024):
                f.write(chunk)
    else:
        raise Exception(f"Failed to download model: {response.status_code}")

def load_model(checkpoint_path):
    model = models.resnet50(pretrained=False)
    model.fc = nn.Linear(model.fc.in_features, 10)  # Adjust for number of classes
    model.load_state_dict(torch.load(checkpoint_path))
    return model

def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    criterion = nn.CrossEntropyLoss()
    optimizer = Adam(model.parameters(), lr=learning_rate)

    model.train()
    for epoch in range(num_epochs):
        for images, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(images)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

def main():
    model_url = 'https://example.com/path/to/model.pth'
    model_path = 'model.pth'
    dataset_dir = 'path/to/custom/dataset'

    download_model(model_url, model_path)
    model = load_model(model_path)

    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
    ])

    custom_dataset = CustomDataset(root_dir=dataset_dir, transform=transform)
    train_loader = DataLoader(custom_dataset, batch_size=32, shuffle=True)

    fine_tune_model(model, train_loader)

if __name__ == '__main__':
    main()